import { useMemo, useState } from 'react';
import './App.css';

const books = [
  {
    id: 1,
    name: 'Uvod u programiranje',
    author: 'Milan Tair',
    image: 'https://covers.openlibrary.org/b/isbn/9780262033848-L.jpg',
    description:
      'Knjiga je namenjena studentima koji prvi put uce osnove programiranja i algoritamskog razmisljanja.',
    category: 'Strucna literatura',
    city: 'Novi Sad',
    availableFrom: '2026-06-01',
    owner: 'Ana D.',
    rating: 5,
    numReviews: 12,
    status: 'Dostupna',
  },
  {
    id: 2,
    name: 'Uvod u mikroprocesorske sisteme',
    author: 'Petar Knezevic',
    image: 'https://covers.openlibrary.org/b/isbn/9780130609049-L.jpg',
    description:
      'Ocuvana skripta za pripremu kolokvijuma i ispita iz mikroprocesorskih sistema.',
    category: 'Skripta',
    city: 'Beograd',
    availableFrom: '2026-06-10',
    owner: 'Marko S.',
    rating: 4.5,
    numReviews: 8,
    status: 'Dostupna',
  },
  {
    id: 3,
    name: 'Na Drini cuprija',
    author: 'Ivo Andric',
    image: 'https://covers.openlibrary.org/b/isbn/9788683583628-L.jpg',
    description:
      'Klasik domace knjizevnosti, pogodan za skolsko citanje i ljubitelje istorijskih romana.',
