function Rating({ value, text }) {
  return (
    <div className="rating" aria-label={`Ocena ${value}`}>
      {[1, 2, 3, 4, 5].map((star) => (
        <span key={star}>{value >= star ? '★' : value >= star - 0.5 ? '☆' : '☆'}</span>
      ))}
      {text && <span className="rating-text">{text}</span>}
    </div>
  );
}

function Header({ cartCount, user, screen, setScreen, onLogout }) {
  return (
    <header className="site-header">
      <div className="container nav-shell">
        <button className="brand" type="button" onClick={() => setScreen('home')}>
          <span className="brand-mark">RK</span>
          <span>
            <strong>Razmena knjiga</strong>
            <small>Fakultet tehnickih nauka u Novom Sadu</small>
          </span>
        </button>

        <nav className="main-nav" aria-label="Navigacija">
          <button className={screen === 'home' ? 'active' : ''} type="button" onClick={() => setScreen('home')}>
            Pocetna
          </button>
          <button className={screen === 'cart' ? 'active' : ''} type="button" onClick={() => setScreen('cart')}>
            Korpa <span className="badge">{cartCount}</span>
          </button>
          {user ? (
            <button className={screen === 'profile' ? 'active' : ''} type="button" onClick={() => setScreen('profile')}>
              {user.name}
            </button>
          ) : (
            <button className={screen === 'login' ? 'active' : ''} type="button" onClick={() => setScreen('login')}>
              Prijava
            </button>
          )}
          {user?.isAdmin && (
            <button className={screen === 'admin' ? 'active' : ''} type="button" onClick={() => setScreen('admin')}>
              Admin
            </button>
          )}
          {user && (
            <button type="button" onClick={onLogout}>
              Odjava
            </button>
          )}
        </nav>
      </div>
    </header>
  );
}

function ProductCard({ book, onOpen }) {
  return (
    <article className="product-card">
      <button className="image-link" type="button" onClick={() => onOpen(book.id)}>
        <img src={book.image} alt={book.name} />
      </button>
      <div className="product-body">
        <button className="title-link" type="button" onClick={() => onOpen(book.id)}>
          <strong>{book.name}</strong>
        </button>
        <p>{book.author}</p>
        <Rating value={book.rating} text={`${book.numReviews} recenzija`} />
        <h3>{book.city}</h3>
      </div>
    </article>
  );
}

function HomeScreen({ onOpen }) {
  const [category, setCategory] = useState('Sve');
  const [query, setQuery] = useState('');

  const categories = ['Sve', ...new Set(books.map((book) => book.category))];
  const filteredBooks = useMemo(
    () =>
      books.filter((book) => {
        const byCategory = category === 'Sve' || book.category === category;
        const byQuery = `${book.name} ${book.author} ${book.city}`.toLowerCase().includes(query.toLowerCase());
        return byCategory && byQuery;
      }),
    [category, query],
  );

  return (
    <>
      <section className="hero">
        <div>
          <h1>Pronadji knjigu koja je vec prosla kroz necije omiljene stranice.</h1>
        </div>
      </section>

      <div className="toolbar">
        <h2>Nove knjige</h2>
        <div className="filters-row">
          <input
            type="search"
            placeholder="Pretraga knjiga"
            value={query}
            onChange={(event) => setQuery(event.target.value)}
          />
          <select value={category} onChange={(event) => setCategory(event.target.value)}>
            {categories.map((item) => (
              <option key={item}>{item}</option>
            ))}
          </select>
        </div>
      </div>

      <section className="product-grid">
        {filteredBooks.map((book) => (
          <ProductCard book={book} key={book.id} onOpen={onOpen} />
        ))}
      </section>
    </>
  );
}

function ProductScreen({ book, onBack, onAddToCart }) {
  return (
    <section className="product-screen">
      <button className="back-button" type="button" onClick={onBack}>
        Nazad
      </button>
      <div className="product-detail">
        <img src={book.image} alt={book.name} />
        <div>
          <h1>{book.name}</h1>
          <Rating value={book.rating} text={`${book.numReviews} recenzija`} />
          <p>{book.description}</p>
          <dl>
            <div>
              <dt>Autor</dt>
              <dd>{book.author}</dd>
            </div>
            <div>
              <dt>Kategorija</dt>
              <dd>{book.category}</dd>
            </div>
            <div>
              <dt>Vlasnik</dt>
              <dd>{book.owner}</dd>
            </div>
            <div>
              <dt>Dostupno od</dt>
              <dd>{book.availableFrom}</dd>
            </div>
          </dl>
        </div>
        <aside className="exchange-card">
          <div>
            <span>Status</span>
            <strong>{book.status}</strong>
          </div>
          <div>
            <span>Grad</span>
            <strong>{book.city}</strong>
          </div>
          <button disabled={book.status !== 'Dostupna'} type="button" onClick={() => onAddToCart(book)}>
            Dodaj u korpu za razmenu
          </button>
        </aside>
      </div>
    </section>
  );
}

function CheckoutSteps({ active }) {
  const steps = ['Prijava', 'Podaci o razmeni', 'Pregled zahteva'];

  return (
    <ol className="checkout-steps">
      {steps.map((step, index) => (
        <li className={index <= active ? 'enabled' : ''} key={step}>
          {step}
        </li>
      ))}
    </ol>
  );
}

function CartScreen({ cartItems, onRemove, onCheckout }) {
  const totalDays = cartItems.reduce((sum, item) => sum + item.days, 0);

  return (
    <section className="cart-layout">
      <div>
        <h1>Korpa za razmenu</h1>
        {cartItems.length === 0 ? (
          <p className="message">Korpa je prazna. Vrati se na pocetnu i izaberi knjigu.</p>
        ) : (
          <div className="cart-list">
            {cartItems.map((item) => (
              <article key={item.id}>
                <img src={item.image} alt={item.name} />
                <div>
                  <strong>{item.name}</strong>
                  <span>{item.author}</span>
                </div>
                <span>{item.days} dana</span>
                <button type="button" onClick={() => onRemove(item.id)}>
                  Obrisi
                </button>
              </article>
            ))}
          </div>
        )}
      </div>
      <aside className="summary-card">
        <h2>Ukupno: {cartItems.length} knjiga</h2>
        <p>Predvidjeno trajanje razmene: {totalDays} dana</p>
        <button disabled={cartItems.length === 0} type="button" onClick={onCheckout}>
          Nastavi razmenu
        </button>
      </aside>
    </section>
  );
}

